// ── CONFIG ────────────────────────────────────────────────────────────────────
const API    = window.location.origin;
const canvas = document.getElementById('gc');
let ctx      = canvas.getContext('2d');   // let — ModelRace swaps this per slot
const W = 480, H = 720;
const ROAD_L = 75, ROAD_R = 405;
const ROAD_W = ROAD_R - ROAD_L;

let state, animId;
const keys = { left: false, right: false };

// ── AI / RL state ─────────────────────────────────────────────────────────────
const ai = { on: false, pending: false, entropy: 1.0, episode: 0,
             recording: false, showSensors: false,
             buffer: [], BATCH: 30 };
const EVAL_SEEDS = [42, 500, 456, 789, 1337, 2024, 7, 99, 314, 1000]; // 123 replaced with 500
let selectedSeed = 42;
function pickRandomSeed() {
  return EVAL_SEEDS[Math.floor(Math.random() * EVAL_SEEDS.length)];
}

// ── IL Flow state ──────────────────────────────────────────────────────────────
const ilFlow = { active: false, onboardShown: false, demoCount: 0 };

// ── Seeded PRNG (for reproducible obstacle sequences) ─────────────────────────
let _rngState = 0;
function seedRng(s) { _rngState = (s || Date.now()) >>> 0; }
function rng() {
  _rngState = (Math.imul(1664525, _rngState) + 1013904223) >>> 0;
  return _rngState / 4294967296;
}

// ── Ghost recorder (stores last human run for Compare mode) ───────────────────
let currentSeed = Date.now();
const ghost = { seed: null, frames: [], duration: 0, hasData: false };

//  ANIMATED MENU BACKGROUND
(function initMenuBg() {
  const canvas = document.getElementById('menu-bg');
  const ctx = canvas.getContext('2d');
  let time = 0;

  function resize() {
    canvas.width = window.innerWidth;
    canvas.height = window.innerHeight;
  }
  resize();
  window.addEventListener('resize', resize);

  const stars = Array.from({ length: 180 }, () => ({
    x: Math.random(), y: Math.random() * 0.5,
    r: Math.random() * 1.4 + 0.2,
    a: Math.random() * 0.55 + 0.15,
    speed: Math.random() * 2 + 1,
  }));
  const streaks = Array.from({ length: 18 }, (_, i) => ({
    side: i % 2 === 0 ? -1 : 1,
    xOff: Math.sin(i * 2.3) * 0.5 + 0.5,
    phase: Math.random(),
    speed: 0.4 + Math.random() * 0.4,
  }));

  function drawMenuFrame() {
    if (document.getElementById('menu-screen').classList.contains('hidden')) {
      requestAnimationFrame(drawMenuFrame);
      return;
    }
    const Wc = canvas.width, Hc = canvas.height;

    const sky = ctx.createLinearGradient(0, 0, 0, Hc * 0.55);
    sky.addColorStop(0, '#04030c');
    sky.addColorStop(1, '#0a071a');
    ctx.fillStyle = sky;
    ctx.fillRect(0, 0, Wc, Hc);

    const vx = Wc * 0.5, vy = Hc * 0.40, hw = Wc * 0.27;
    const roadGrad = ctx.createLinearGradient(0, vy, 0, Hc);
    roadGrad.addColorStop(0, '#08061a');
    roadGrad.addColorStop(1, '#0d0b22');
    ctx.fillStyle = roadGrad;
    ctx.beginPath();
    ctx.moveTo(vx - 12, vy); ctx.lineTo(vx + 12, vy);
    ctx.lineTo(Wc / 2 + hw, Hc * 1.05); ctx.lineTo(Wc / 2 - hw, Hc * 1.05);
    ctx.closePath(); ctx.fill();

    const hg = ctx.createRadialGradient(Wc / 2, vy, 0, Wc / 2, vy, Wc * 0.5);
    hg.addColorStop(0, 'rgba(139,92,246,0.18)');
    hg.addColorStop(0.4, 'rgba(80,40,180,0.05)');
    hg.addColorStop(1, 'transparent');
    ctx.fillStyle = hg;
    ctx.fillRect(0, vy - 100, Wc, 200);

    [[-1, '#8b5cf6'], [1, '#f59e0b']].forEach(([side, color]) => {
      const x1 = vx + side * 12, x2 = Wc / 2 + side * hw;
      const g = ctx.createLinearGradient(x1, vy, x2, Hc);
      g.addColorStop(0, color + '00');
      g.addColorStop(0.5, color + '66');
      g.addColorStop(1, color + 'bb');
      ctx.strokeStyle = g; ctx.lineWidth = 2.5;
      ctx.shadowColor = color; ctx.shadowBlur = 6;
      ctx.beginPath(); ctx.moveTo(x1, vy); ctx.lineTo(x2, Hc); ctx.stroke();
      ctx.shadowBlur = 0;
    });

    for (let i = 0; i < 14; i++) {
      const t = ((i / 14) + time * 0.38) % 1;
      const y = vy + t * (Hc - vy);
      const dw = 2 + t * 7, dh = 6 + t * 32;
      const da = Math.min(t * 2.2, 0.85);
      ctx.fillStyle = `rgba(245,158,11,${da * 0.7})`;
      ctx.fillRect(Wc / 2 - dw / 2, y - dh / 2, dw, dh);
    }

    stars.forEach(s => {
      const tw = 0.75 + Math.sin(time * s.speed + s.x * 12) * 0.25;
      ctx.beginPath();
      ctx.arc(s.x * Wc, s.y * Hc, s.r, 0, Math.PI * 2);
      ctx.fillStyle = `rgba(200,180,255,${s.a * tw})`;
      ctx.fill();
    });

    streaks.forEach(s => {
      const ph = (s.phase + time * s.speed) % 1;
      if (ph < 0.04) return;
      const xBase = s.side > 0 ? 0.56 + s.xOff * 0.14 : 0.44 - s.xOff * 0.14;
      const x = xBase * Wc, y = ph * Hc;
      const len = ph * 55 + 10;
      const a = Math.min(ph * 1.8, 0.15);
      const g = ctx.createLinearGradient(x, y - len, x, y);
      g.addColorStop(0, 'transparent');
      g.addColorStop(1, `rgba(139,92,246,${a})`);
      ctx.strokeStyle = g; ctx.lineWidth = 1.5;
      ctx.beginPath(); ctx.moveTo(x, y - len); ctx.lineTo(x, y); ctx.stroke();
    });

    const fog = ctx.createLinearGradient(0, Hc * 0.72, 0, Hc);
    fog.addColorStop(0, 'transparent');
    fog.addColorStop(1, 'rgba(4,3,12,0.97)');
    ctx.fillStyle = fog;
    ctx.fillRect(0, Hc * 0.72, Wc, Hc * 0.28);

    time += 0.016;
    requestAnimationFrame(drawMenuFrame);
  }
  drawMenuFrame();
})();

// ══════════════════════════════════════════════════════════════════════════════
//  ANIMATED WORLD BACKGROUND (grid + particles behind game)
// ══════════════════════════════════════════════════════════════════════════════
(function initWorldBg() {
  const wc = document.getElementById('world-bg');
  const wctx = wc.getContext('2d');
  let wW, wH, wFrame = 0;

  const nodes = [];
  const NUM_NODES = 70;
  const pulses = [];  // travelling pulses along connections

  function resize() {
    wW = wc.width  = window.innerWidth;
    wH = wc.height = window.innerHeight;
  }
  resize();
  window.addEventListener('resize', resize);

  // Create neural-net-like nodes in layers
  const COLORS = ['#00e5ff', '#0077ff', '#4cff91', '#a855f7', '#ff6f00'];
  for (let i = 0; i < NUM_NODES; i++) {
    nodes.push({
      x: Math.random() * 2000,
      y: Math.random() * 1200,
      vx: (Math.random() - 0.5) * 0.4,
      vy: (Math.random() - 0.5) * 0.4,
      r: 1.5 + Math.random() * 2.5,
      color: COLORS[Math.floor(Math.random() * COLORS.length)],
      alpha: 0.15 + Math.random() * 0.35,
      pulse: Math.random() * Math.PI * 2  // phase offset for pulsing
    });
  }

  // Hex grid helper
  function drawHexGrid(ctx, w, h, size, offset, alpha) {
    ctx.strokeStyle = `rgba(0, 229, 255, ${alpha})`;
    ctx.lineWidth = 0.5;
    const hStep = size * 1.5;
    const vStep = size * Math.sqrt(3);
    for (let row = -1; row * vStep < h + vStep; row++) {
      for (let col = -1; col * hStep < w + hStep; col++) {
        const cx = col * hStep + (offset * 0.3) % hStep;
        const cy = row * vStep + (col % 2 ? vStep / 2 : 0) + (offset * 0.15) % vStep;
        ctx.beginPath();
        for (let k = 0; k < 6; k++) {
          const a = Math.PI / 3 * k - Math.PI / 6;
          const px = cx + size * Math.cos(a);
          const py = cy + size * Math.sin(a);
          k === 0 ? ctx.moveTo(px, py) : ctx.lineTo(px, py);
        }
        ctx.closePath();
        ctx.stroke();
      }
    }
  }

  function drawWorldBg() {
    wFrame++;
    wctx.fillStyle = '#08080f';
    wctx.fillRect(0, 0, wW, wH);

    // Layer 1: Hex grid (subtle)
    drawHexGrid(wctx, wW, wH, 40, wFrame, 0.018);

    // Layer 2: Finer grid overlay
    const gridSize = 80;
    const gridOff = (wFrame * 0.2) % gridSize;
    wctx.strokeStyle = 'rgba(0, 229, 255, 0.012)';
    wctx.lineWidth = 1;
    for (let x = -gridSize + gridOff; x < wW; x += gridSize) {
      wctx.beginPath(); wctx.moveTo(x, 0); wctx.lineTo(x, wH); wctx.stroke();
    }
    for (let y = -gridSize + gridOff; y < wH; y += gridSize) {
      wctx.beginPath(); wctx.moveTo(0, y); wctx.lineTo(wW, y); wctx.stroke();
    }

    // Layer 3: Nodes (pulsing dots)
    const t = wFrame * 0.02;
    nodes.forEach(n => {
      n.x += n.vx;
      n.y += n.vy;
      if (n.x < -20) n.x = wW + 20;
      if (n.x > wW + 20) n.x = -20;
      if (n.y < -20) n.y = wH + 20;
      if (n.y > wH + 20) n.y = -20;

      const pulseAlpha = n.alpha * (0.6 + 0.4 * Math.sin(t + n.pulse));
      const pulseR = n.r * (0.8 + 0.2 * Math.sin(t * 1.5 + n.pulse));

      // Glow
      wctx.beginPath();
      wctx.arc(n.x, n.y, pulseR * 4, 0, Math.PI * 2);
      wctx.fillStyle = `rgba(0, 229, 255, ${pulseAlpha * 0.04})`;
      wctx.fill();

      // Core
      wctx.beginPath();
      wctx.arc(n.x, n.y, pulseR, 0, Math.PI * 2);
      wctx.fillStyle = n.color.replace(')', `,${pulseAlpha})`).replace('rgb', 'rgba').replace('#', '');
      // Use hex with alpha
      wctx.globalAlpha = pulseAlpha;
      wctx.fillStyle = n.color;
      wctx.fill();
      wctx.globalAlpha = 1;
    });

    // Layer 4: Connections (neural net style)
    const CONNECT_DIST = 180;
    for (let i = 0; i < nodes.length; i++) {
      for (let j = i + 1; j < nodes.length; j++) {
        const dx = nodes[i].x - nodes[j].x;
        const dy = nodes[i].y - nodes[j].y;
        const dist = Math.sqrt(dx * dx + dy * dy);
        if (dist < CONNECT_DIST) {
          const alpha = (1 - dist / CONNECT_DIST) * 0.09;
          wctx.strokeStyle = `rgba(0, 229, 255, ${alpha})`;
          wctx.lineWidth = 0.6;
          wctx.beginPath();
          wctx.moveTo(nodes[i].x, nodes[i].y);
          wctx.lineTo(nodes[j].x, nodes[j].y);
          wctx.stroke();
        }
      }
    }

    // Layer 5: Travelling pulses along random connections
    if (wFrame % 30 === 0 && pulses.length < 15) {
      const a = Math.floor(Math.random() * nodes.length);
      const b = Math.floor(Math.random() * nodes.length);
      if (a !== b) {
        const dx = nodes[a].x - nodes[b].x;
        const dy = nodes[a].y - nodes[b].y;
        if (Math.sqrt(dx*dx+dy*dy) < CONNECT_DIST * 1.5) {
          pulses.push({ from: a, to: b, t: 0, speed: 0.01 + Math.random() * 0.02,
                        color: COLORS[Math.floor(Math.random() * COLORS.length)] });
        }
      }
    }
    for (let p = pulses.length - 1; p >= 0; p--) {
      const pulse = pulses[p];
      pulse.t += pulse.speed;
      if (pulse.t > 1) { pulses.splice(p, 1); continue; }
      const n1 = nodes[pulse.from], n2 = nodes[pulse.to];
      const px = n1.x + (n2.x - n1.x) * pulse.t;
      const py = n1.y + (n2.y - n1.y) * pulse.t;
      const a = Math.sin(pulse.t * Math.PI) * 0.6;  // fade in/out
      wctx.beginPath();
      wctx.arc(px, py, 2.5, 0, Math.PI * 2);
      wctx.fillStyle = pulse.color;
      wctx.globalAlpha = a;
      wctx.fill();
      // trail glow
      wctx.beginPath();
      wctx.arc(px, py, 8, 0, Math.PI * 2);
      wctx.fillStyle = pulse.color;
      wctx.globalAlpha = a * 0.15;
      wctx.fill();
      wctx.globalAlpha = 1;
    }

    // Radial vignette
    const grad = wctx.createRadialGradient(wW/2, wH/2, wH*0.1, wW/2, wH/2, wH*0.8);
    grad.addColorStop(0, 'transparent');
    grad.addColorStop(1, 'rgba(8, 8, 15, 0.55)');
    wctx.fillStyle = grad;
    wctx.fillRect(0, 0, wW, wH);

    requestAnimationFrame(drawWorldBg);
  }
  drawWorldBg();
})();

// ══════════════════════════════════════════════════════════════════════════════
//  MENU → GAME TRANSITION
// ══════════════════════════════════════════════════════════════════════════════
function showRecordingBar() {
  const bar = document.getElementById('ai-info-bar');
  if (bar) {
    bar.classList.remove('hidden');
    document.getElementById('ai-info-text').textContent = 'Recording demos';
  }
}

function hideRecordingBar() {
  const bar = document.getElementById('ai-info-bar');
  if (bar) bar.classList.add('hidden');
}

function startGameFromMenu(recordDemos = false) {
  SoundSystem.init();
  SoundSystem.playClick();
  document.getElementById('menu-screen').classList.add('hidden');
  document.getElementById('game-screen').classList.add('visible');
  setTimeout(() => {
    resetGame();
    ilFlow.onboardShown = true;
    ilFlow.active = recordDemos;
    ai.recording = recordDemos;
    if (recordDemos) showRecordingBar();
    else hideRecordingBar();
    state.running = true;
    loop();
  }, 600);
}

document.getElementById('menu-start').addEventListener('click', () => startGameFromMenu(false));
document.getElementById('menu-record').addEventListener('click', () => startGameFromMenu(true));

function goToMenu() {
  if (animId) cancelAnimationFrame(animId);
  SoundSystem.stopEngine();
  keys.left = keys.right = false;
  state.running = false;
  state.paused = false;
  document.getElementById('pause-menu').classList.remove('open');
  document.getElementById('overlay').style.display = 'none';
  document.getElementById('game-screen').classList.remove('visible');
  const menu = document.getElementById('menu-screen');
  menu.classList.remove('hidden');
}

function pauseGame() {
  if (!state || !state.running || state.over) return;
  state.running = false;
  state.paused = true;
  keys.left = keys.right = false;
  if (animId) cancelAnimationFrame(animId);
  SoundSystem.stopEngine();
  document.getElementById('pause-menu').classList.add('open');
  document.getElementById('btn-pause').classList.add('active');
  document.getElementById('btn-pause').textContent = '▶';
}

function resumeGame() {
  if (!state || !state.paused) return;
  state.paused = false;
  state.running = true;
  document.getElementById('pause-menu').classList.remove('open');
  document.getElementById('btn-pause').classList.remove('active');
  document.getElementById('btn-pause').textContent = '⏸';
  loop();
}

function restartGame() {
  if (animId) cancelAnimationFrame(animId);
  document.getElementById('pause-menu').classList.remove('open');
  document.getElementById('overlay').style.display = 'none';
  document.getElementById('btn-pause').classList.remove('active');
  document.getElementById('btn-pause').textContent = '⏸';
  resetGame();
  state.running = true;
  state.paused = false;
  loop();
}

