// ── Local neural-net inference (zero latency — runs entirely in the browser) ───
// Mirrors the Python DQN forward pass: relu(W1·x+b1) → relu(W2·h1+b2) → W3·h2+b3
const localNet = {
  W1: null, b1: null, W2: null, b2: null, W3: null, b3: null,
  nIn: 30, nH: 128, nOut: 3,
  loaded: false,

  load(w) {
    this.W1 = w.W1; this.b1 = w.b1;
    this.W2 = w.W2; this.b2 = w.b2;
    this.W3 = w.W3; this.b3 = w.b3;
    this.nH = w.W1.length;   // detect hidden size from weights (128 or 256)
    this.loaded = true;
    console.log('[localNet] weights loaded — running inference in-browser at 60 fps');
  },

  forward(state) {
    const {W1,b1,W2,b2,W3,b3,nIn,nH,nOut} = this;
    // H1 = relu(W1 @ state + b1)
    const H1 = new Float32Array(nH);
    for (let i = 0; i < nH; i++) {
      let s = b1[i];
      const row = W1[i];
      for (let j = 0; j < nIn; j++) s += row[j] * state[j];
      H1[i] = s > 0 ? s : 0;
    }
    // H2 = relu(W2 @ H1 + b2)
    const H2 = new Float32Array(nH);
    for (let i = 0; i < nH; i++) {
      let s = b2[i];
      const row = W2[i];
      for (let j = 0; j < nH; j++) s += row[j] * H1[j];
      H2[i] = s > 0 ? s : 0;
    }
    // Q = W3 @ H2 + b3
    const Q = new Float32Array(nOut);
    for (let i = 0; i < nOut; i++) {
      let s = b3[i];
      const row = W3[i];
      for (let j = 0; j < nH; j++) s += row[j] * H2[j];
      Q[i] = s;
    }
    return Q;
  },

  // Greedy action — same as greedy_eval() in train3_grid.py
  act(state) {
    const Q = this.forward(state);
    let best = 0;
    for (let i = 1; i < this.nOut; i++) if (Q[i] > Q[best]) best = i;
    return best;
  }
};

// ── 5x3 Occupancy Grid Sensors (replaces raycasts — zero blind spots) ─────────
const GRID_COLS = 5;
const GRID_ROWS = 3;
const GRID_ROW_BANDS = [[0, 120], [120, 260], [260, 430]];
const N_OBS_SLOTS = 4;

function getGridOccupancy() {
    const colW    = ROAD_W / GRID_COLS;
    const playerY = state.player.y + state.player.h / 2;
    const grid    = [];
    for (const [near, far] of GRID_ROW_BANDS) {
        const yBottom = playerY - near;
        const yTop    = playerY - far;
        for (let ci = 0; ci < GRID_COLS; ci++) {
            const cellX1 = ROAD_L + ci * colW;
            const cellX2 = cellX1 + colW;
            let hit = 0;
            for (const o of state.obstacles) {
                const ox1 = o.x - o.w / 2, ox2 = o.x + o.w / 2;
                const oy1 = o.y,            oy2 = o.y + o.h;
                if (ox2 > cellX1 && ox1 < cellX2 && oy2 > yTop && oy1 < yBottom) {
                    hit = 1; break;
                }
            }
            grid.push(hit);
        }
    }
    return grid;  // 15 values
}

function getFeatures() {
    // 30-dim obs — must match train3_grid.py HeadlessGame.get_features() exactly
    // [0] player_x  [1] velocity  [2-16] 5x3 grid  [17] spawn_timer  [18-29] 4 slots
    const p    = state.player;
    const base = [
        (p.x - ROAD_L) / ROAD_W,
        Math.tanh(p.vx / 8),
        ...getGridOccupancy(),
        state.spawnTimer / state.spawnInterval,
    ];
    // 4-slot obstacle lookahead (closest first = highest Y)
    const sorted = [...state.obstacles].sort((a, b) => b.y - a.y).slice(0, N_OBS_SLOTS);
    const slots  = [];
    for (const o of sorted) {
        slots.push((o.x - ROAD_L) / ROAD_W);
        slots.push(Math.max(0, p.y - o.y) / H);
        slots.push(o.w / ROAD_W);
    }
    while (slots.length < N_OBS_SLOTS * 3) slots.push(0.5, 1.0, 0.12);
    return [...base, ...slots];  // length = 30
}

function computeReward() {
    const feat     = getFeatures();
    const nearRow  = feat.slice(2, 7);          // 5 cells of closest grid row
    const clear    = 1.0 - Math.max(...nearRow);
    const progress = Math.min(1.0, state.score / 2500);
    let r = 0.10 + 0.15 * progress;
    r += clear * 0.4;
    const wallProx = Math.min(feat[0], 1.0 - feat[0]);
    if (wallProx < 0.08) r -= (0.08 - wallProx) / 0.08 * 1.5;
    return r;
}

// Grid visualiser (shown when ai.showSensors is true)
function drawSensors() {
    if (!ai.showSensors) return;
    const colW    = ROAD_W / GRID_COLS;
    const playerY = state.player.y + state.player.h / 2;
    const feat    = getFeatures();
    let fi = 2;  // grid values start at index 2
    for (const [near, far] of GRID_ROW_BANDS) {
        for (let ci = 0; ci < GRID_COLS; ci++) {
            const x   = ROAD_L + ci * colW;
            const y   = playerY - far;
            const h   = far - near;
            const hit = feat[fi++];
            ctx.fillStyle   = hit ? 'rgba(255,60,60,0.35)' : 'rgba(60,255,120,0.12)';
            ctx.fillRect(x, y, colW, h);
            ctx.strokeStyle = hit ? 'rgba(255,60,60,0.7)'  : 'rgba(60,255,120,0.3)';
            ctx.lineWidth   = 1;
            ctx.strokeRect(x, y, colW, h);
        }
    }
}

// ── Network calls ─────────────────────────────────────────────────────────────
async function post(path, body) {
  try {
    const r = await fetch(API + path, {
      method: 'POST', headers: {'Content-Type':'application/json'},
      body: JSON.stringify(body)
    });
    return await r.json();
  } catch { return null; }
}

async function flushBuffer() {
  if (!ai.buffer.length) return;
  const batch = ai.buffer.splice(0);
  const res = await post('/record_batch', batch);
  if (res) {
    document.getElementById('demo-val').textContent = res.recorded;
    ilFlow.demoCount = res.recorded;
  }
}

async function checkServer() {
  try {
    const r = await fetch(API + '/status');
    const d = await r.json();
    document.getElementById('srv-status').textContent = 'Online';
    const dot = document.getElementById('srv-dot');
    dot.classList.add('online');
    const newEp = d.episode || 0;
    const prevEp = parseInt(document.getElementById('ep-val').textContent) || 0;
    ai.episode = newEp;
    document.getElementById('ep-val').textContent   = newEp;
    document.getElementById('eps-val').textContent  = (d.entropy != null ? d.entropy : 1.0).toFixed(3);
    document.getElementById('avg-val').textContent  = d.avg_score || 0;
    document.getElementById('demo-val').textContent = d.il_demos  || 0;
    // Wire live RL scores into training graph
    if (ai.on && newEp > prevEp && d.avg_score) {
      TrainingGraph.push(d.avg_score);
    }
  } catch {
    document.getElementById('srv-status').textContent = 'Offline';
    document.getElementById('srv-dot').classList.remove('online');
  }
}

async function rlStep() {
  // ── Local inference path (zero latency) ──────────────────────────────────────
  // When a model is loaded into the browser, run the forward pass here directly.
  // This matches train3_grid.py greedy_eval(): instant, synchronous, every frame.
  if (localNet.loaded) {
    const action = localNet.act(getFeatures());
    keys.left  = action === 0;
    keys.right = action === 2;
    ai.entropy = 0;   // greedy = no exploration
    document.getElementById('eps-val').textContent = '0.000';
    return;
  }

  // ── Server inference path (fallback when no model loaded yet) ────────────────
  if (ai.pending) return;
  ai.pending = true;
  const reward = computeReward();
  const res = await post('/step', { state: getFeatures(), reward, done: false });
  ai.pending = false;
  if (!res || !ai.on) return;
  keys.left  = res.action === 0;
  keys.right = res.action === 2;
  ai.entropy = res.entropy != null ? res.entropy : ai.entropy;
  document.getElementById('eps-val').textContent = ai.entropy.toFixed(3);
}

async function rlCrash(score) {
  const wasCompare = state.compareMode;
  keys.left = keys.right = false;
  if (ai.recording) await flushBuffer();

  if (localNet.loaded) {
    // Local mode: no replay buffer to update, just log the episode score
    await post('/episode_end', { score });
  } else {
    // Server mode: send terminal transition so the replay buffer gets the crash
    await post('/step',        { state: getFeatures(), reward: -50, done: true });
    await post('/episode_end', { score });
  }

  const el = document.getElementById('ep-val');
  const newEp = parseInt(el.textContent || 0) + 1;
  el.textContent = newEp;
  ai.episode = newEp;
  if (ai.on) {
    setTimeout(() => {
      if (animId) cancelAnimationFrame(animId);
      if (wasCompare) {
        seedRng(ghost.seed);
        resetGame(true);
        state.compareMode = true;
      } else {
        resetGame();
      }
      state.running = true;
      document.getElementById('overlay').style.display = 'none';
      loop();
    }, 200);
  }
}

function setRLButtonState() {
  const btn = document.getElementById('btn-ai');
  btn.innerHTML = ai.on
    ? '<span class="ctrl-mega-icon">&#129302;</span><div class="ctrl-mega-body"><div class="ctrl-mega-title">RL Agent</div><div class="ctrl-mega-sub">● Active</div></div><span class="rl-switch" aria-hidden="true"><i></i></span>'
    : '<span class="ctrl-mega-icon">&#129302;</span><div class="ctrl-mega-body"><div class="ctrl-mega-title">RL Agent</div><div class="ctrl-mega-sub">○ Offline</div></div><span class="rl-switch" aria-hidden="true"><i></i></span>';
  btn.classList.toggle('active-ai', ai.on);
}

function updateLevelPips() {
  document.querySelectorAll('.hud-lives i').forEach((pip, i) => {
    pip.classList.toggle('active', i < Math.min(state.level, 3));
  });
}

async function openHumanCrashPrompt() {
  if (!ai.on && ai.recording && ilFlow.active) await flushBuffer();
}

