// ── Touch controls ────────────────────────────────────────────────────────────
const cw = document.getElementById('canvas-wrap');
cw.addEventListener('touchstart', e => {
  Array.from(e.touches).forEach(t => {
    const x = t.clientX - cw.getBoundingClientRect().left;
    if (x < W/2) keys.left = true; else keys.right = true;
  });
  e.preventDefault();
}, {passive:false});
cw.addEventListener('touchend', e => {
  if (e.touches.length === 0) { keys.left = false; keys.right = false; }
  e.preventDefault();
}, {passive:false});

// ══════════════════════════════════════════════════════════════════════════════
//  DEBUG MODE (toggle with ` key)
// ══════════════════════════════════════════════════════════════════════════════
let debugMode = false;
let debugFps = 0, debugFrameCount = 0, debugLastTime = performance.now();

function updateDebug() {
  if (!debugMode || !state.running) return;
  debugFrameCount++;
  const now = performance.now();
  if (now - debugLastTime >= 1000) {
    debugFps = debugFrameCount;
    debugFrameCount = 0;
    debugLastTime = now;
  }

  const p = state.player;
  const feat = getFeatures();
  const reward = computeReward();
  const action = keys.left ? 'LEFT' : keys.right ? 'RIGHT' : 'NONE';

  const el = document.getElementById('debug-overlay');
  const grid = feat.slice(2, 17);
  const gridStr = [0,1,2].map(row =>
    '  ' + grid.slice(row*5, row*5+5).map(v => v ? '█' : '░').join(' ')
  ).join('\n');
  el.textContent =
    `FPS: ${debugFps}\n` +
    `Frame: ${state.frame}\n` +
    `Score: ${state.score}  Lvl: ${state.level}\n` +
    `─────────────────\n` +
    `Player X: ${p.x.toFixed(1)}  VX: ${p.vx.toFixed(2)}\n` +
    `Action: ${action}\n` +
    `─────────────────\n` +
    `5×3 Grid (row0=near):\n` +
    `${gridStr}\n` +
    `  car_x:  ${feat[0].toFixed(3)}\n` +
    `  speed:  ${feat[1].toFixed(3)}\n` +
    `  spawn:  ${feat[17].toFixed(3)}\n` +
    `  slot0:  x=${feat[18].toFixed(2)} d=${feat[19].toFixed(2)} w=${feat[20].toFixed(2)}\n` +
    `  slot1:  x=${feat[21].toFixed(2)} d=${feat[22].toFixed(2)} w=${feat[23].toFixed(2)}\n` +
    `─────────────────\n` +
    `Reward: ${reward.toFixed(2)}\n` +
    `Epsilon: ${ai.entropy.toFixed(4)}\n` +
    `AI: ${ai.on ? 'ON' : 'OFF'}  REC: ${ai.recording ? 'ON' : 'OFF'}\n` +
    `Obstacles: ${state.obstacles.length}`;
}

// Update debug every 3 frames
const origLoop = loop;
const _origDrawFrame = drawFrame;
const hookedDrawFrame = function() {
  _origDrawFrame();
  if (debugMode && state.running) updateDebug();
};
// Monkey-patch drawFrame
drawFrame = hookedDrawFrame;

document.addEventListener('keydown', e => {
  if (e.key === '`' || e.key === '~') {
    debugMode = !debugMode;
    document.getElementById('debug-overlay').classList.toggle('visible', debugMode);
  }
});

