const ftEpisodesSlider = document.getElementById('sl-ft-episodes');
const ftEpisodesVal    = document.getElementById('val-ft-episodes');
ftEpisodesSlider.addEventListener('input', () => {
  ftEpisodesVal.textContent = ftEpisodesSlider.value;
});

document.getElementById('btn-fast-train').addEventListener('click', () => {
  document.getElementById('fast-train-modal').classList.add('open');
});
document.getElementById('fast-train-close').addEventListener('click', () => {
  document.getElementById('fast-train-modal').classList.remove('open');
});
document.getElementById('fast-train-modal').addEventListener('click', e => {
  if (e.target.id === 'fast-train-modal') {
    document.getElementById('fast-train-modal').classList.remove('open');
  }
});

let ftPollInterval = null;

document.getElementById('ft-start-btn').addEventListener('click', async () => {
  const episodes = parseInt(ftEpisodesSlider.value);
  const btn = document.getElementById('ft-start-btn');
  btn.innerHTML = 'Starting...';
  btn.disabled = true;

  const res = await post('/train_fast', { episodes });
  if (!res || !res.ok) {
    btn.innerHTML = 'Start Training';
    btn.disabled = false;
    alert(res ? res.error : 'Server offline');
    return;
  }

  document.getElementById('ft-progress-area').style.display = 'block';
  btn.innerHTML = 'Training...';

  // Poll status
  if (ftPollInterval) clearInterval(ftPollInterval);
  ftPollInterval = setInterval(async () => {
    try {
      const r = await fetch(API + '/train_fast_status');
      const d = await r.json();
      const pct = d.total > 0 ? (d.episode / d.total * 100) : 0;
      document.getElementById('ft-bar').style.width = pct + '%';

      const scores = d.scores || [];
      const last20 = scores.slice(-20);
      const avg = last20.length ? (last20.reduce((a,b)=>a+b,0)/last20.length).toFixed(0) : '—';
      document.getElementById('ft-stats').textContent =
        `Episode ${d.episode}/${d.total}  |  Best: ${d.best_score}  |  Avg20: ${avg}`;

      // Update training graph
      if (d.scores && d.scores.length) {
        TrainingGraph.scores = d.scores;
        TrainingGraph.draw();
      }

      // Show snapshot chips
      const snaps = d.snapshots || [];
      const miniEl = document.getElementById('ft-snapshots-mini');
      miniEl.innerHTML = snaps.map(s =>
        `<span class="ft-snap-chip">Ep ${s.episode} (avg: ${s.avg_score})</span>`
      ).join('');

      if (!d.running && d.episode > 0) {
        clearInterval(ftPollInterval);
        ftPollInterval = null;
        btn.innerHTML = 'Done!';
        btn.disabled = false;
        setTimeout(() => { btn.innerHTML = 'Start Training'; }, 2000);
        checkServer();
      }
    } catch {}
  }, 1000);
});

