async function refreshSnapshots() {
  const listEl = document.getElementById('snapshots-list');
  try {
    const r = await fetch(API + '/list_snapshots');
    const d = await r.json();
    const snaps = d.snapshots || [];
    if (snaps.length === 0) {
      listEl.innerHTML = '<div class="ft-stats">No snapshots yet. Run Fast Train first.</div>';
      return;
    }
    listEl.innerHTML = snaps.map(s => `
      <div class="snap-row" data-file="${s.file}">
        <div class="snap-info">
          <span class="snap-ep">Generation ${s.episode}</span>
          <span class="snap-detail">Avg Score: ${s.avg_score} &nbsp;|&nbsp; Best: ${s.best_score}</span>
        </div>
        <button class="snap-load-btn" data-file="${s.file}">Load</button>
      </div>
    `).join('');

    // Attach click handlers
    listEl.querySelectorAll('.snap-load-btn').forEach(btn => {
      btn.addEventListener('click', async (e) => {
        e.stopPropagation();
        const file = btn.dataset.file;
        btn.textContent = 'Loading...';
        const res = await post('/load_snapshot', { file });
        if (res && res.loaded) {
          ai.episode = res.episode || 0;
          document.getElementById('ep-val').textContent = res.episode;
          // Pull weights so inference runs locally at full frame rate
          try {
            const wr = await fetch(API + '/get_weights');
            const wd = await wr.json();
            localNet.load(wd.weights);
            document.getElementById('eps-val').textContent = '0.000';
            btn.textContent = 'Loaded! (local)';
          } catch {
            btn.textContent = 'Loaded!';
          }
          setTimeout(() => { btn.textContent = 'Load'; }, 1500);
        } else {
          btn.textContent = 'Failed';
          setTimeout(() => { btn.textContent = 'Load'; }, 1500);
        }
      });
    });
  } catch {
    listEl.innerHTML = '<div class="ft-stats">Server offline</div>';
  }
}

