// ══════════════════════════════════════════════════════════════════════════════
//  TRAINING GRAPH
// ══════════════════════════════════════════════════════════════════════════════
const TrainingGraph = {
  canvas: document.getElementById('train-graph'),
  tctx: null,
  scores: [],

  init() {
    this.tctx = this.canvas.getContext('2d');
    this.draw();
  },

  push(score) {
    this.scores.push(score);
    this.draw();
  },

  draw() {
    const c = this.canvas;
    const g = this.tctx;
    if (!g) return;
    const CW = c.width, CH = c.height;
    const PAD_L = 28, PAD_T = 6, PAD_B = 16, PAD_R = 4;
    const pw = CW - PAD_L - PAD_R;
    const ph = CH - PAD_T - PAD_B;

    g.clearRect(0, 0, CW, CH);
    g.fillStyle = 'rgba(0,0,0,0.3)';
    g.fillRect(0, 0, CW, CH);

    if (!this.scores.length) {
      g.fillStyle = '#334';
      g.font = '9px Rajdhani, sans-serif';
      g.textAlign = 'center';
      g.fillText('No data yet', CW/2, CH/2 + 3);
      g.textAlign = 'left';
      return;
    }

    const scores = this.scores;
    const maxVal = Math.max(...scores, 100);
    const minVal = 0;
    const range = maxVal - minVal || 1;

    // Compute avg20
    const avg20 = scores.map((_, i) => {
      const slice = scores.slice(Math.max(0, i-19), i+1);
      return slice.reduce((a,b)=>a+b,0) / slice.length;
    });

    const sx = i => PAD_L + (i / Math.max(scores.length-1, 1)) * pw;
    const sy = v => PAD_T + ph - ((v - minVal) / range) * ph;

    // Grid line
    g.strokeStyle = 'rgba(255,255,255,0.04)';
    g.lineWidth = 1;
    g.setLineDash([3,3]);
    const mid = sy((maxVal + minVal) / 2);
    g.beginPath(); g.moveTo(PAD_L, mid); g.lineTo(CW-PAD_R, mid); g.stroke();
    g.setLineDash([]);

    // Score fill gradient
    if (scores.length > 1) {
      const fillGrad = g.createLinearGradient(0, PAD_T, 0, PAD_T+ph);
      fillGrad.addColorStop(0, 'rgba(0,229,255,0.12)');
      fillGrad.addColorStop(1, 'rgba(0,229,255,0)');
      g.beginPath();
      g.moveTo(sx(0), PAD_T+ph);
      scores.forEach((v,i) => g.lineTo(sx(i), sy(v)));
      g.lineTo(sx(scores.length-1), PAD_T+ph);
      g.closePath();
      g.fillStyle = fillGrad;
      g.fill();
    }

    // Score line
    g.strokeStyle = 'rgba(0,229,255,0.7)';
    g.lineWidth = 1;
    if (scores.length > 1) {
      g.beginPath();
      scores.forEach((v,i) => i===0 ? g.moveTo(sx(i),sy(v)) : g.lineTo(sx(i),sy(v)));
      g.stroke();
    }

    // Avg20 line
    g.strokeStyle = 'rgba(76,255,145,0.9)';
    g.lineWidth = 1.5;
    if (avg20.length > 1) {
      g.beginPath();
      avg20.forEach((v,i) => i===0 ? g.moveTo(sx(i),sy(v)) : g.lineTo(sx(i),sy(v)));
      g.stroke();
    }

    // Y-axis labels
    g.fillStyle = '#334';
    g.font = '8px Rajdhani, sans-serif';
    g.textAlign = 'right';
    g.fillText(Math.round(maxVal), PAD_L-3, PAD_T+5);
    g.fillText('0', PAD_L-3, PAD_T+ph+1);
    g.textAlign = 'left';
  }
};

// ══════════════════════════════════════════════════════════════════════════════
//  SOUND SYSTEM — procedural Web Audio API
// ══════════════════════════════════════════════════════════════════════════════
const SoundSystem = {
  ctx: null,
  enabled: true,
  engineNode: null,
  engineGain: null,

  init() {
    if (this.ctx) return;
    try {
      this.ctx = new (window.AudioContext || window.webkitAudioContext)();
    } catch(e) { /* audio not available */ }
  },

  _resume() {
    if (this.ctx && this.ctx.state === 'suspended') this.ctx.resume();
  },

  _guard() {
    return this.enabled && this.ctx;
  },

  playClick() {
    if (!this._guard()) return; this._resume();
    const o = this.ctx.createOscillator();
    const g = this.ctx.createGain();
    o.type = 'sine'; o.frequency.value = 900;
    g.gain.setValueAtTime(0.08, this.ctx.currentTime);
    g.gain.linearRampToValueAtTime(0, this.ctx.currentTime + 0.06);
    o.connect(g); g.connect(this.ctx.destination);
    o.start(); o.stop(this.ctx.currentTime + 0.07);
  },

  playCollision() {
    if (!this._guard()) return; this._resume();
    const buf = this.ctx.createBuffer(1, this.ctx.sampleRate * 0.35, this.ctx.sampleRate);
    const data = buf.getChannelData(0);
    for (let i=0; i<data.length; i++) data[i] = (Math.random()*2-1) * (1 - i/data.length);
    const src = this.ctx.createBufferSource();
    src.buffer = buf;
    const filt = this.ctx.createBiquadFilter();
    filt.type = 'lowpass'; filt.frequency.value = 500;
    const g = this.ctx.createGain();
    g.gain.setValueAtTime(0.5, this.ctx.currentTime);
    g.gain.linearRampToValueAtTime(0, this.ctx.currentTime + 0.35);
    src.connect(filt); filt.connect(g); g.connect(this.ctx.destination);
    src.start(); src.stop(this.ctx.currentTime + 0.36);
  },

  playLevelUp() {
    if (!this._guard()) return; this._resume();
    [440, 554, 659].forEach((freq, i) => {
      const o = this.ctx.createOscillator();
      const g = this.ctx.createGain();
      o.type = 'triangle'; o.frequency.value = freq;
      const t = this.ctx.currentTime + i * 0.1;
      g.gain.setValueAtTime(0, t);
      g.gain.linearRampToValueAtTime(0.18, t + 0.02);
      g.gain.linearRampToValueAtTime(0, t + 0.14);
      o.connect(g); g.connect(this.ctx.destination);
      o.start(t); o.stop(t + 0.15);
    });
  },

  playWin() {
    if (!this._guard()) return; this._resume();
    [523, 659, 784, 1047, 1319].forEach((freq, i) => {
      const o = this.ctx.createOscillator();
      const g = this.ctx.createGain();
      o.type = 'triangle'; o.frequency.value = freq;
      const t = this.ctx.currentTime + i * 0.12;
      const dur = i === 4 ? 0.4 : 0.14;
      g.gain.setValueAtTime(0, t);
      g.gain.linearRampToValueAtTime(0.22, t + 0.02);
      g.gain.linearRampToValueAtTime(0, t + dur);
      o.connect(g); g.connect(this.ctx.destination);
      o.start(t); o.stop(t + dur + 0.01);
    });
  },

  // ── Chiptune background music ──────────────────────────────────────────
  // A-minor pentatonic melody, 120 BPM.  Each entry: [melody_hz, bass_hz, beats]
  _MUSIC: [
    [330,110,0.5],[294,110,0.5],[262,110,0.5],[220,110,0.5],
    [246,123,0.5],[220,123,0.5],[196,123,1.0],
    [220,110,0.5],[262,110,0.5],[294,165,0.5],[330,165,0.5],
    [349,131,0.5],[330,131,0.5],[294,131,1.0],
    [330,110,0.5],[392,110,0.5],[440,165,0.5],[392,165,0.5],
    [349,131,1.0],[330,131,0.5],[294,131,0.5],
    [262,110,0.5],[294,110,0.5],[330,98, 0.5],[294,98, 0.5],
    [262,110,1.5],[220,110,0.5],
  ],
  _musicIdx: 0,
  _musicTimer: null,
  _masterGain: null,

  startEngine() { this._startMusic(); },
  stopEngine()  { this._stopMusic();  },
  setEngineSpeed() { /* no-op — engine speed no longer drives sound */ },

  _startMusic() {
    if (!this._guard()) return; this._resume();
    if (this._musicTimer) return;
    if (!this._masterGain) {
      this._masterGain = this.ctx.createGain();
      this._masterGain.gain.value = 0;
      this._masterGain.connect(this.ctx.destination);
    }
    // fade in
    this._masterGain.gain.cancelScheduledValues(this.ctx.currentTime);
    this._masterGain.gain.linearRampToValueAtTime(1, this.ctx.currentTime + 1.2);
    this._musicIdx = 0;
    this._playMusicStep();
  },

  _stopMusic() {
    clearTimeout(this._musicTimer);
    this._musicTimer = null;
    if (!this._masterGain) return;
    // fade out
    this._masterGain.gain.cancelScheduledValues(this.ctx.currentTime);
    this._masterGain.gain.linearRampToValueAtTime(0, this.ctx.currentTime + 0.5);
  },

  _playMusicStep() {
    if (!this.enabled || !this.ctx || !this._masterGain) return;
    const BPM = 120, spb = 60 / BPM;
    const [mHz, bHz, beats] = this._MUSIC[this._musicIdx % this._MUSIC.length];
    const dur = spb * beats;
    const now = this.ctx.currentTime;

    // Melody — triangle, soft
    const mo = this.ctx.createOscillator();
    const mg = this.ctx.createGain();
    mo.type = 'triangle'; mo.frequency.value = mHz;
    mg.gain.setValueAtTime(0.55, now);
    mg.gain.linearRampToValueAtTime(0, now + dur * 0.75);
    mo.connect(mg); mg.connect(this._masterGain);
    mo.start(now); mo.stop(now + dur * 0.8);

    // Bass — square, quieter
    const bo = this.ctx.createOscillator();
    const bg = this.ctx.createGain();
    bo.type = 'square'; bo.frequency.value = bHz;
    bg.gain.setValueAtTime(0.18, now);
    bg.gain.linearRampToValueAtTime(0, now + dur * 0.6);
    bo.connect(bg); bg.connect(this._masterGain);
    bo.start(now); bo.stop(now + dur * 0.65);

    this._musicIdx++;
    this._musicTimer = setTimeout(() => this._playMusicStep(), (dur - 0.02) * 1000);
  }
};

