document.getElementById('il-decision-pretrain').addEventListener('click', async () => {
  document.getElementById('il-decision-modal').classList.remove('open');
  const pm = document.getElementById('il-progress-modal');
  pm.classList.add('open');
  const bar = document.getElementById('il-progress-bar');
  const stats = document.getElementById('il-progress-stats');
  const resultArea = document.getElementById('il-result-area');
  resultArea.style.display = 'none';
  bar.style.width = '0%';
  stats.textContent = 'Flushing demos to server...';

  await flushBuffer();
  bar.style.width = '3%';
  stats.textContent = 'Training neural network on your demos...';

  await new Promise((resolve) => {
    const es = new EventSource('/pretrain_stream');
    es.onmessage = (e) => {
      const data = JSON.parse(e.data);
      if (data.error) {
        es.close();
        stats.textContent = 'Error: ' + data.error;
        resolve();
        return;
      }
      if (data.done) {
        es.close();
        bar.style.width = '100%';
        const acc = (data.accuracy * 100).toFixed(1);
        document.getElementById('il-result-acc').textContent = acc + '%';
        document.getElementById('il-result-msg').textContent =
          `Trained on ${data.samples} demos. The AI will now fine-tune with PPO — starting with human-level moves!`;
        ai.recording = false;
        ilFlow.active = false;
        hideRecordingBar();
        document.getElementById('il-progress-title').textContent = '✓ Training Complete';
        stats.textContent = 'Done!';
        resultArea.style.display = 'block';
        resolve();
      } else {
        bar.style.width = data.progress + '%';
        stats.textContent = `Epoch ${data.progress}% — Accuracy: ${(data.accuracy * 100).toFixed(1)}%`;
      }
    };
    es.onerror = () => {
      es.close();
      stats.textContent = 'Error: Server offline';
      resolve();
    };
  });
});

