async function refreshILSessions() {
  const listEl = document.getElementById('il-sessions-list');
  try {
    const r = await fetch(API + '/list_il_sessions');
    const d = await r.json();
    const sessions = d.sessions || [];
    if (!sessions.length) {
      listEl.innerHTML = '<div class="ft-stats">No sessions saved yet. Pretrain to create one.</div>';
      return;
    }
    listEl.innerHTML = sessions.map(s => {
      const ts = s.timestamp ? s.timestamp.replace('_', ' ') : 'Unknown';
      const acc = s.accuracy ? (s.accuracy * 100).toFixed(1) + '%' : '—';
      return `<div class="snap-row">
        <div class="snap-info">
          <span class="snap-ep">${ts}</span>
          <span class="snap-detail">Acc: ${acc} &nbsp;|&nbsp; Samples: ${s.sample_count}</span>
        </div>
        <button class="snap-load-btn" data-file="${s.file}">Load</button>
      </div>`;
    }).join('');

    listEl.querySelectorAll('.snap-load-btn').forEach(btn => {
      btn.addEventListener('click', async (e) => {
        e.stopPropagation();
        btn.textContent = 'Loading...';
        const res = await post('/load_il_session', { file: btn.dataset.file });
        if (res && res.loaded) {
          ai.episode = res.episode || 0;
          document.getElementById('ep-val').textContent = ai.episode;
          btn.textContent = 'Loaded!';
          setTimeout(() => { btn.textContent = 'Load'; }, 1500);
        } else {
          btn.textContent = 'Failed';
          setTimeout(() => { btn.textContent = 'Load'; }, 1500);
        }
      });
    });
  } catch {
    listEl.innerHTML = '<div class="ft-stats">Server offline</div>';
  }
}

// ══════════════════════════════════════════════════════════════════════════════
//  MODEL RACE — 3-game side-by-side comparison (identical obstacle sequence)
// ══════════════════════════════════════════════════════════════════════════════

// Per-slot colours: [car highlight, car body, label/HUD colour]
const RACE_SLOT_CFG = [
  { carHi: '#00e5ff', carBody: '#004d56', label: '#00e5ff' },  // cyan
  { carHi: '#4cff91', carBody: '#0d3d1a', label: '#4cff91' },  // green
  { carHi: '#ffd700', carBody: '#4a3600', label: '#ffd700' },  // gold
];

// Create an independent neural-network inference object
function makeRaceNet() {
  const nIn = 30, nOut = 3;
  return {
    W1:null,b1:null,W2:null,b2:null,W3:null,b3:null,loaded:false,nH:256,
    load(w){ this.W1=w.W1;this.b1=w.b1;this.W2=w.W2;this.b2=w.b2;this.W3=w.W3;this.b3=w.b3;this.nH=w.W1.length;this.loaded=true; },
    forward(st){
      const nH=this.nH;
      const H1=new Float32Array(nH);
      for(let i=0;i<nH;i++){let s=this.b1[i];const r=this.W1[i];for(let j=0;j<nIn;j++)s+=r[j]*st[j];H1[i]=s>0?s:0;}
      const H2=new Float32Array(nH);
      for(let i=0;i<nH;i++){let s=this.b2[i];const r=this.W2[i];for(let j=0;j<nH;j++)s+=r[j]*H1[j];H2[i]=s>0?s:0;}
      const Q=new Float32Array(nOut);
      for(let i=0;i<nOut;i++){let s=this.b3[i];const r=this.W3[i];for(let j=0;j<nH;j++)s+=r[j]*H2[j];Q[i]=s;}
      return Q;
    },
    act(st){ const Q=this.forward(st);let b=0;for(let i=1;i<nOut;i++)if(Q[i]>Q[b])b=i;return b; }
  };
}

// Independent game-state for each race slot
function createRaceState() {
  return {
    frame:0,score:0,over:false,level:1,running:true,
    player:{x:W/2,y:H-130,w:42,h:70,vx:0},
    obstacles:[],roadOffset:0,particles:[],
    spawnInterval:60,spawnTimer:0,baseSpeed:3.5,
    spawnIdx:0,compareMode:false,levelUpMsg:null,best:0
  };
}

// Feature extraction that works on any state object (same maths as getFeatures())
function getFeaturesFrom(s) {
  const colW=ROAD_W/GRID_COLS, pY=s.player.y+s.player.h/2;
  const grid=[];
  for(const [near,far] of GRID_ROW_BANDS){
    const yB=pY-near,yT=pY-far;
    for(let ci=0;ci<GRID_COLS;ci++){
      const cx1=ROAD_L+ci*colW,cx2=cx1+colW;
      let hit=0;
      for(const o of s.obstacles){
        if((o.x+o.w/2)>cx1&&(o.x-o.w/2)<cx2&&(o.y+o.h)>yT&&o.y<yB){hit=1;break;}
      }
      grid.push(hit);
    }
  }
  const p=s.player;
  const base=[(p.x-ROAD_L)/ROAD_W,Math.tanh(p.vx/8),...grid,s.spawnTimer/s.spawnInterval];
  const sorted=[...s.obstacles].sort((a,b)=>b.y-a.y).slice(0,N_OBS_SLOTS);
  const sl=[];
  for(const o of sorted)sl.push((o.x-ROAD_L)/ROAD_W,Math.max(0,p.y-o.y)/H,o.w/ROAD_W);
  while(sl.length<N_OBS_SLOTS*3)sl.push(0.5,1.0,0.12);
  return [...base,...sl];
}

// One physics tick for a race slot (same logic as the main loop)
function stepRaceSlot(slot) {
  const s=slot.state;
  if(s.over)return;
  const action=slot.net.loaded?slot.net.act(getFeaturesFrom(s)):1;  // stay if no model
  s.frame++;s.roadOffset+=s.baseSpeed;
  const p=s.player;
  if(action===0)p.vx-=1.2;
  if(action===2)p.vx+=1.2;
  p.vx*=0.75;
  p.x=Math.max(ROAD_L+p.w/2+2,Math.min(ROAD_R-p.w/2-2,p.x+p.vx));
  s.spawnTimer++;
  if(s.spawnTimer>=s.spawnInterval){
    s.spawnTimer=0;
    const _seq=SPAWN_SEQUENCES[selectedSeed]||SPAWN_SEQUENCES[42];
    const e=_seq[s.spawnIdx%_seq.length];
    const _lvlSpd=3.5+(s.level-1)*0.3;
    const idx=s.spawnIdx%Assets.obsImgs.length;
    s.spawnIdx++;
    s.obstacles.push({
      x:e[0],y:-90,w:40,h:68,speed:_lvlSpd+0.3+rng()*1.0,
      color:  ['#e74c3c','#e67e22','#9b59b6','#3498db','#1abc9c'][idx%5],
      bodyColor:['#c0392b','#d35400','#8e44ad','#2980b9','#16a085'][idx%5],
      img:Assets.obsImgs[idx]
    });
  }
  s.obstacles.forEach(o=>o.y+=o.speed);
  s.obstacles=s.obstacles.filter(o=>o.y<H+100);
  // Collision check
  for(const o of s.obstacles){
    if(collides(p,o)){
      s.over=true;s.running=false;
      // Explosion particles into slot state
      const cols=['#ff1744','#ff6f00','#ffea00','#ff8a65','#fff'];
      for(let i=0;i<22;i++){
        const ang=Math.random()*Math.PI*2,spd=1+Math.random()*4.5;
        s.particles.push({x:p.x,y:p.y+p.h/2,vx:Math.cos(ang)*spd,vy:Math.sin(ang)*spd-2,
          r:2+Math.random()*4,color:cols[i%5],life:28+Math.random()*18,maxLife:46});
      }
      return;
    }
  }
  s.score++;
  s.level=Math.min(5,1+Math.floor(s.score/500));
  if(s.score>=2500){s.over=true;s.running=false;}
}

// Draw one race slot onto its own canvas.
// Temporarily swaps global ctx/state so the existing draw helpers work unmodified.
function drawRaceSlot(slot) {
  const savedCtx=ctx, savedState=state, savedAiOn=ai.on;
  ctx=slot.ctx; state=slot.state; ai.on=false;

  ctx.clearRect(0,0,W,H);
  drawRoad();

  // Obstacles
  slot.state.obstacles.forEach(o=>drawCar(o.x,o.y,o.w,o.h,o.color,o.bodyColor,false,o.img));

  // Player car in slot colour (isPlayer=false avoids hardcoded cyan)
  const p=slot.state.player;
  drawCar(p.x,p.y,p.w,p.h,slot.cfg.carHi,slot.cfg.carBody,false,null);

  // "AI" label above car
  ctx.save();
  ctx.fillStyle=slot.cfg.label; ctx.font='bold 9px Orbitron,monospace';
  ctx.textAlign='center';
  ctx.shadowColor=slot.cfg.label; ctx.shadowBlur=8;
  ctx.fillText('AI',p.x,p.y-6);
  ctx.shadowBlur=0; ctx.restore();

  // Particles (explosion on crash)
  drawParticles();

  // Score HUD strip at top
  ctx.save();
  ctx.fillStyle='rgba(0,0,0,0.45)'; ctx.fillRect(0,0,W,30);
  ctx.fillStyle='#fff'; ctx.font='bold 15px Orbitron,monospace'; ctx.textAlign='center';
  ctx.fillText(slot.state.score,W/2,20);
  // Level tag
  ctx.fillStyle=slot.cfg.label; ctx.font='8px Orbitron,monospace'; ctx.textAlign='left';
  ctx.fillText('LVL '+slot.state.level,ROAD_L+4,16);
  // Mini level bar
  const lbX=ROAD_R-68,lbW=60;
  ctx.fillStyle='#222'; ctx.fillRect(lbX,10,lbW,5);
  const fill=slot.state.level>=5?1:(slot.state.score%500)/500;
  ctx.fillStyle=slot.cfg.label; ctx.fillRect(lbX,10,lbW*fill,5);
  ctx.restore();

  // CRASHED / FINISHED overlay
  if(slot.state.over){
    const won=slot.state.score>=2500;
    ctx.save();
    ctx.fillStyle='rgba(0,0,0,0.62)'; ctx.fillRect(0,0,W,H);
    ctx.fillStyle=won?'#ffd700':'#ff4444';
    ctx.font='bold 24px Orbitron,monospace'; ctx.textAlign='center';
    ctx.shadowColor=ctx.fillStyle; ctx.shadowBlur=20;
    ctx.fillText(won?'🏆 FINISHED':'💥 CRASHED',W/2,H/2-14);
    ctx.shadowBlur=0;
    ctx.fillStyle='#999'; ctx.font='13px Orbitron,monospace';
    ctx.fillText('Score: '+slot.state.score,W/2,H/2+18);
    ctx.restore();
  }

  ctx=savedCtx; state=savedState; ai.on=savedAiOn;
}

// ── ModelRace controller ──────────────────────────────────────────────────────
const ModelRace = {
  active: false,
  animId: null,
  slots: null,   // array of 3 slot objects

  // Build slot array from the 3 canvases
  init() {
    this.slots = [0,1,2].map(i => ({
      canvas: document.getElementById(`race-canvas-${i}`),
      ctx:    document.getElementById(`race-canvas-${i}`).getContext('2d'),
      net:    makeRaceNet(),
      state:  createRaceState(),
      label:  `Slot ${i+1}`,
      cfg:    RACE_SLOT_CFG[i],
      file:   null
    }));
  },

  // Fetch a snapshot JSON and load its weights into a slot's network
  async loadSnapshot(slotIdx, file) {
    try {
      const r = await fetch(`${API}/snapshots/${file}`);
      const d = await r.json();
      this.slots[slotIdx].net.load(d.weights);
      this.slots[slotIdx].file = file;
      return true;
    } catch { return false; }
  },

  // Begin the race
  start() {
    this.active = true;
    // Reset all 3 games to frame 0 (same starting state)
    this.slots.forEach((slot,i) => {
      slot.state = createRaceState();
      // Update DOM labels
      document.getElementById(`race-label-${i}`).textContent = slot.label;
      document.getElementById(`race-canvas-badge-${i}`).textContent = slot.label;
      document.getElementById(`race-score-${i}`).textContent = '0';
    });
    document.getElementById('race-result-bar').style.display = 'none';
    document.getElementById('race-replay-btn').style.display = 'none';
    // Pause main game, show race screen
    if (animId) { cancelAnimationFrame(animId); animId = null; }
    SoundSystem.stopEngine();
    document.getElementById('game-screen').style.display = 'none';
    document.getElementById('model-race-screen').classList.remove('hidden');
    this._loop();
  },

  // Return to normal game view
  stop() {
    this.active = false;
    if (this.animId) { cancelAnimationFrame(this.animId); this.animId = null; }
    document.getElementById('model-race-screen').classList.add('hidden');
    document.getElementById('game-screen').style.display = '';
    // Resume / restart main game
    if (!state.running) { resetGame(); state.running = true; loop(); }
    else loop();
  },

  // Restart all 3 from scratch (same obstacle sequence from idx=0)
  replay() {
    this.slots.forEach((slot,i) => {
      slot.state = createRaceState();
      document.getElementById(`race-score-${i}`).textContent = '0';
    });
    document.getElementById('race-result-bar').style.display = 'none';
    document.getElementById('race-replay-btn').style.display = 'none';
    this._loop();
  },

  _loop() {
    if (!this.active) return;
    // Advance all 3 games
    this.slots.forEach(slot => stepRaceSlot(slot));
    // Draw all 3
    this.slots.forEach(slot => drawRaceSlot(slot));
    // Update header score chips
    this.slots.forEach((slot,i) => {
      document.getElementById(`race-score-${i}`).textContent = slot.state.score;
    });
    // If all 3 done → show results, offer replay
    if (this.slots.every(s => s.state.over)) {
      this._showResults();
      return;
    }
    this.animId = requestAnimationFrame(() => this._loop());
  },

  _showResults() {
    const ranked = this.slots
      .map((s,i) => ({ label:s.label, score:s.state.score, cfg:s.cfg, i }))
      .sort((a,b) => b.score - a.score);
    const medals = ['🥇','🥈','🥉'];
    const el = document.getElementById('race-result-bar');
    el.innerHTML =
      '<span style="font-family:Orbitron,monospace;font-size:10px;color:#667;letter-spacing:2px;white-space:nowrap">RESULTS:</span>' +
      ranked.map((s,r) =>
        `<span class="race-result-chip" style="border-color:${s.cfg.label};color:${s.cfg.label}">
           ${medals[r]} ${s.label} <strong>${s.score}</strong>
         </span>`
      ).join('');
    el.style.display = 'flex';
    el.style.alignItems = 'center';
    el.style.gap = '8px';
    document.getElementById('race-replay-btn').style.display = '';
  }
};

// ── Populate snapshot dropdowns in the race setup modal ──────────────────────
async function populateRaceSelects() {
  const emptyOpt = '<option value="">— no model (stays centre) —</option>';
  try {
    const r = await fetch(API + '/list_snapshots');
    const d = await r.json();
    const snaps = d.snapshots || [];
    if (!snaps.length) {
      [0,1,2].forEach(i => {
        document.getElementById(`race-sel-${i}`).innerHTML =
          '<option value="">No snapshots yet — run Fast Train first</option>';
      });
      return;
    }
    const opts = emptyOpt + snaps.map(s =>
      `<option value="${s.file}">Gen ${s.episode} — avg ${s.avg_score} — best ${s.best_score}</option>`
    ).join('');
    [0,1,2].forEach(i => {
      const sel = document.getElementById(`race-sel-${i}`);
      sel.innerHTML = opts;
      // Pre-select early / mid / latest snapshots automatically
      const picks = [0, Math.floor((snaps.length-1)/2), snaps.length-1];
      if (snaps[picks[i]]) sel.value = snaps[picks[i]].file;
    });
  } catch {
    [0,1,2].forEach(i => {
      document.getElementById(`race-sel-${i}`).innerHTML =
        '<option value="">Server offline</option>';
    });
  }
}

// ── Race Setup Modal buttons ──────────────────────────────────────────────────
document.getElementById('btn-model-race').addEventListener('click', async () => {
  await populateRaceSelects();
  document.getElementById('model-race-modal').classList.add('open');
});

// Also reachable from the Snapshots modal footer
document.getElementById('btn-race-from-snaps').addEventListener('click', async () => {
  document.getElementById('snapshots-modal').classList.remove('open');
  await populateRaceSelects();
  document.getElementById('model-race-modal').classList.add('open');
});

document.getElementById('model-race-close').addEventListener('click', () => {
  document.getElementById('model-race-modal').classList.remove('open');
});
document.getElementById('model-race-modal').addEventListener('click', e => {
  if (e.target.id === 'model-race-modal')
    document.getElementById('model-race-modal').classList.remove('open');
});

document.getElementById('race-start-btn').addEventListener('click', async () => {
  const btn = document.getElementById('race-start-btn');
  btn.innerHTML = '<span class="icon">⏳</span> Loading models...';
  btn.disabled = true;

  ModelRace.init();

  for (let i = 0; i < 3; i++) {
    const file  = document.getElementById(`race-sel-${i}`).value;
    const label = document.getElementById(`race-lbl-${i}`).value.trim() || `Lane ${i+1}`;
    ModelRace.slots[i].label = label;
    if (file) await ModelRace.loadSnapshot(i, file);
  }

  btn.innerHTML = '<span class="icon">▶</span> Start Race';
  btn.disabled = false;
  document.getElementById('model-race-modal').classList.remove('open');
  ModelRace.start();
});

// ── Race Screen control buttons ───────────────────────────────────────────────
document.getElementById('race-exit-btn').addEventListener('click', () => ModelRace.stop());
document.getElementById('race-replay-btn').addEventListener('click', () => ModelRace.replay());

// ── Init ──────────────────────────────────────────────────────────────────────
TrainingGraph.init();
checkServer();
setInterval(checkServer, 5000);
drawFrame();
